{
  "query": "mutation CreatePaymentRequest($amount: MoneyInput!, $payerReference: String!, $beneficiaryReference: String!) { clientPaymentInitiationRequestCreate(input: { amount: $amount, payerReference: $payerReference, beneficiaryReference: $beneficiaryReference, beneficiary: { bankAccount: { name: \"Acme Pty Ltd\", bankId: fnb, accountNumber: \"62000000000\" } } }) { paymentInitiationRequest { id url } } }",
  "variables": {
    "amount": { "quantity": 100.00, "currency": "ZAR" },
    "payerReference": "order-1234",
    "beneficiaryReference": "ACME-1234"
  }
}

{
  "query": "query GetPaymentRequestStatus($id: ID!) { node(id: $id) { ... on PaymentInitiationRequest { id state { __typename } } } }",
  "variables": {
    "id": "payment-initiation-request/01H..."
  }
}

{
  "query": "mutation LinkAccount($input: PaymentAuthorizationRequestCreateInput!) { clientPaymentAuthorizationRequestCreate(input: $input) { paymentAuthorizationRequest { id url } } }",
  "variables": {
    "input": { "beneficiary": { "bankAccount": { "name": "Acme Pty Ltd", "bankId": "fnb", "accountNumber": "62000000000" } } }
  }
}

{
  "query": "query VerifyBankAccount($input: BankAccountVerificationInput!) { verifyBankAccountDetails(input: $input) { accountVerificationResult accountHolderVerified accountNumberVerified accountOpen } }",
  "variables": {
    "input": { "accountNumber": "62000000000", "bankId": "fnb", "accountHolder": { "name": "Jane Doe" } }
  }
}

{
  "query": "query UserTransactions { user { bankAccounts { accountNumber currentBalance transactions(first: 50) { edges { node { id amount reference description date runningBalance } } } } } }"
}

{
  "query": "mutation CreateDisbursement($input: DisbursementInitiateInput!) { clientDisbursementInitiate(input: $input) { disbursement { id status } } }",
  "variables": {
    "input": { "amount": { "quantity": 250.00, "currency": "ZAR" }, "nonce": "d290f1ee-6c54-4b01-90e6-d701748f0851", "beneficiaryReference": "PAYOUT-9876", "beneficiary": { "bankAccount": { "name": "Jane Doe", "bankId": "capitec", "accountNumber": "1700000000" } } }
  }
}

{
  "query": "mutation CreateRefund($input: RefundInitiateInput!) { clientRefundInitiate(input: $input) { refund { id status } } }",
  "variables": {
    "input": { "originalPaymentId": "payment-initiation-request/01H...", "amount": { "quantity": 100.00, "currency": "ZAR" }, "nonce": "a1b2c3d4-0000-1111-2222-333344445555", "reason": "duplicate" }
  }
}

{
  "query": "mutation AddWebhook($url: URL!, $secret: String!) { clientWebhookAdd(input: { url: $url, secret: $secret }) { webhook { id url } } }",
  "variables": {
    "url": "https://example.com/webhooks/stitch",
    "secret": "whsec_example"
  }
}
